// Copyright 2019 The Go Authors. All rights reserved.// Use of this source code is governed by a BSD-style// license that can be found in the LICENSE file.package proto// Bool stores v in a new bool value and returns a pointer to it.l(v bool) *bool { return &v }// Int stores v in a new int32 value and returns a pointer to it.//// Deprecated: Use Int32 instead.(v int) *int32 { return Int32(int32(v)) }// Int32 stores v in a new int32 value and returns a pointer to it.32(v int32) *int32 { return &v }// Int64 stores v in a new int64 value and returns a pointer to it.64(v int64) *int64 { return &v }// Uint32 stores v in a new uint32 value and returns a pointer to it.t32(v uint32) *uint32 { return &v }// Uint64 stores v in a new uint64 value and returns a pointer to it.t64(v uint64) *uint64 { return &v }// Float32 stores v in a new float32 value and returns a pointer to it.at32(v float32) *float32 { return &v }// Float64 stores v in a new float64 value and returns a pointer to it.at64(v float64) *float64 { return &v }// String stores v in a new string value and returns a pointer to it.ing(v string) *string { return &v }